SELECT s.name AS teacherName, SUM(ls.dec_lesson_count) AS totalHours FROM lesson_schedule ls INNER JOIN staff s ON FIND_IN_SET(s.id, ls.teacher_ids) > 0
AND ls.start_date >= #{startDate}
AND ls.end_date <= #{endDate}
GROUP BY s.id, s.name ORDER BY totalHours DESC

SELECT COUNT(DISTINCT s.id)
FROM lesson_schedule ls
INNER JOIN staff s ON FIND_IN_SET(s.id, ls.teacher_ids) > 0


        AND ls.start_date >= #{startDate}


        AND ls.end_date <= #{endDate}
